import{_ as a,o as e,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const s="/images/schrift012.jpg",n="/images/schrift013.jpg",p="/images/schrift014.jpg",d=JSON.parse('{"title":"Devanāgarī = देवनागरी","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/schrift07.md","filePath":"lektionen/schrift07.md"}'),u={name:"lektionen/schrift07.md"};function h(c,r,o,l,b,g){return e(),t("div",null,[...r[0]||(r[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="devanagari-देवनागरी" tabindex="-1">Devanāgarī = देवनागरी <a class="header-anchor" href="#devanagari-देवनागरी" aria-label="Permalink to &quot;Devanāgarī = देवनागरी&quot;">​</a></h1><h2 id="schriftubung-7" tabindex="-1">Schriftübung 7 <a class="header-anchor" href="#schriftubung-7" aria-label="Permalink to &quot;Schriftübung 7&quot;">​</a></h2><p><img src="'+s+'" alt=""></p><p>Beispiele für r vor Konsonant:</p><p>र्क  rka, र्च rca, र्ट rṭa, र्त rta, र्प rpa, र्श rśa, र्ह rha, र्का rkā, र्कि, rki, र्की rkī, र्कु rku, र्के rke, र्कै rkai, र्को rko, र्कौ rkau, र्कं rkaṃ, र्कां rkāṃ, र्किं rkiṃ, र्कीं rkīṃ,  र्कुं rkuṃ, र्कें rkeṃ, र्कैं rkaiṃ, र्कौं rkauṃ</p><p>Zur Schreibung:</p><p><img src="'+n+'" alt=""></p><p>r nach Konsonant: /</p><ul><li><p>bei Buchstaben mit senkrechtem Abschlussstrich: / an senkrechtem Abschlussstrich</p></li><li><p>bei anderen Buchstaben: unten am Buchstaben</p></li></ul><blockquote><p>क्र ख्र ग्र घ्र ङ्र्<br> kra khra gra ghra ṅra</p><p>च्र छ्र ज्र झ्र ञ्र<br> cra, chra, jra, jhra, ñra</p><p>ट्र ठ्र ड्र ढ्र् ढ्र स्ण्र<br> ṭra ṭhra ḍra ḍhra ṇra</p><p>त्र थ्र द्र ध्र न्र<br> tra thra dra dhra nra</p><p>प्र फ्र ब्र भ्र म्र<br> pra phra bra bhra mra</p><p>य्र व्र<br> yra vra</p><p>श्र ष्र स्र<br> śra ṣra sra</p><p>ह्र<br> hra</p></blockquote><p>Zur Schreibung:</p><p><img src="'+p+'" alt=""></p><h2 id="ubung" tabindex="-1">Übung <a class="header-anchor" href="#ubung" aria-label="Permalink to &quot;Übung&quot;">​</a></h2><p>A) Schreiben Sie in Devanāgarī und geben Sie die Übersetzung an (setzt Lektion 8 voraus):</p><p>śravaṇa, darśana, kāraṇa, sarga, krodhaḥ, netram, śruti, kurvate. śudraḥ śṛṇoti. śrutirvedaḥ. dhenurviśati. sādhurguruḥ. gururyajate. kavirmāghaḥ.</p><p>B) Lesen, transliterieren und übersetzen Sie:</p><p>श्रुतिः | गुर्वी | क्रुध् | शृणोति | कविर्भारविः | कविर्हर्षदेवः | पशुर्धेनुः | शूद्रेतरा | श्रोत्रम् ||</p>',18)])])}const m=a(u,[["render",h]]);export{d as __pageData,m as default};
